#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    # Only run if the tool is Bash
    if ev.get("tool_name") != "Bash":
        return 0

    # Defensive lookup for the command
    tool_input = ev.get("tool_input") or {}
    cmd = tool_input.get("command", "")

    # Check for the problematic pattern: starts with pnpm test but doesn't contain the correct ci script
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Warning: Running `pnpm test` will open an interactive watcher and may time out. Please use `pnpm test:ci` instead for non-interactive CI testing.", file=sys.stderr)
        return 2  # Block the command

    return 0

if __name__ == "__main__":
    sys.exit(main())

