#!/usr/bin/env python3
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") not in ("Write", "Edit"):
        return 0

    inp = ev.get("tool_input") or {}

    # Determine which content to check (Write uses 'content', Edit uses 'new_string')
    content_to_check = inp.get("content") or inp.get("new_string", "")

    if not content_to_check:
        return 0

    # Simple check for mixed tabs and spaces (a common violation)
    if "\t" in content_to_check and " " in content_to_check:
        print("Warning: Detected mixed tabs and spaces in the proposed change. Please ensure consistent indentation (e.g., using only spaces) before proceeding.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
